import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';

import { HomeComponent } from './home/home.component';
import { XOComponent } from './xo/xo.component';
import { RpsComponent } from './rps/rps.component';
import { GuessTheNumberComponent } from './guess-the-number/guess-the-number.component';

const routes: Routes = [
  {path: 'Home', component: HomeComponent},
  {path: 'Tik-Tak-Toe', component: XOComponent},
  {path: 'Rock-Paper-Scisors', component: RpsComponent},
  {path: 'Guess-The-Number', component: GuessTheNumberComponent},
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
